    await c.query("DELETE FROM audit_events WHERE account_id = $1", [accountId]);

    // INSERT workflow_state
    await c.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, "Strategic account rescue", status, nextStep, riskSummary]
    );

    // INSERT owner_tasks (one per owner group)
    if (q) {
      const dueAt = new Date(now);
      dueAt.setHours(16, 0, 0, 0);
      for (const owner of owners) {
        await c.query(
          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
          [requestId, accountId, owner, `${owner} recovery review for ${acct.name}`, dueAt.toISOString(), "open"]
        );
      }

      // INSERT customer_messages (one customer-safe message, no internal ids/codes)
      const messageBody = `Dear ${acct.name} team, we are reaching out to inform you that our account management team has identified several areas requiring immediate attention on your account. Our dedicated recovery team is actively working to address outstanding items including regulatory compliance review, payment reconciliation, shipment delays, and support escalations. We have assigned specialized teams to each area and they will be in contact with you shortly to resolve these matters. Your account is a high priority for us and we are committed to resolving all open items as quickly as possible. Please expect follow-up communications from our Legal, Finance, Customer Success, and Support teams today. Thank you for your continued partnership.`;
      await c.query(
        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
        [requestId, accountId, messageBody]
      );

      // INSERT audit_events (one customer-visible event)
      await c.query(
        "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
        [requestId, accountId, `Escalation workflow initiated. ${riskSummary}. Recovery owners assigned: ${owners.join(", ")}.`, now, true]
      );
    }
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

