```javascript
import { withDb } from "./db.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const nowDate = new Date(now);

    const account = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
    if (!account) throw new Error("No account found");

    const accountId = account.account_id;
    const [invoices, shipments, regulatoryFlags, supportCases, usagePeriods, reqRow] = await Promise.all([
      client.query("SELECT * FROM invoices WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM shipments WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM regulatory_flags WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM support_cases WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM usage_periods WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM workflow_requests WHERE account_id = $1 LIMIT 1", [accountId]).then(r => r.rows[0]),
    ]);

    // Derive risk signals in display order
    const signals = [];

    if (regulatoryFlags.some(f => f.status === "open"))
      signals.push("Regulatory hold");

    if (invoices.some(inv => inv.status !== "paid" && new Date(inv.due_date) < nowDate && inv.amount_cents >= 2500000))
      signals.push("Overdue invoice");

    if (shipments.some(s => !s.delivered_date && new Date(s.sla_date) < nowDate))
      signals.push("Delayed shipment");

    if (supportCases.some(c => c.status === "open" && (c.severity === "high" || c.severity === "critical")))
      signals.push("Escalated support");

    if (usagePeriods.some(u => Number(u.current_period_units) <= Number(u.prior_period_units) * 0.7))
      signals.push("Usage decline");

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(account.tier) && signals.length > 0;

    // Owner routing (deduplicated, fixed order)
    const ownerSet = new Set();
