import { withDb } from "./db.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const nowDate = new Date(now);

    const account = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
    if (!account) throw new Error("No account found");

    const accountId = account.account_id;
    const [invoices, shipments, regulatoryFlags, supportCases, usagePeriods, reqRow] = await Promise.all([
      client.query("SELECT * FROM invoices WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM shipments WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM regulatory_flags WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM support_cases WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM usage_periods WHERE account_id = $1", [accountId]).then(r => r.rows),
      client.query("SELECT * FROM workflow_requests WHERE account_id = $1 LIMIT 1", [accountId]).then(r => r.rows[0]),
    ]);

    // Derive risk signals in display order
    const signals = [];

    if (regulatoryFlags.some(f => f.status === "open"))
      signals.push("Regulatory hold");

    if (invoices.some(inv => inv.status !== "paid" && new Date(inv.due_date) < nowDate && inv.amount_cents >= 2500000))
      signals.push("Overdue invoice");

    if (shipments.some(s => !s.delivered_date && new Date(s.sla_date) < nowDate))
      signals.push("Delayed shipment");

    if (supportCases.some(c => c.status === "open" && (c.severity === "high" || c.severity === "critical")))
      signals.push("Escalated support");

    if (usagePeriods.some(u => Number(u.current_period_units) <= Number(u.prior_period_units) * 0.7))
      signals.push("Usage decline");

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(account.tier) && signals.length > 0;

    // Owner routing (deduplicated, fixed order)
    const ownerSet = new Set();
    if (signals.includes("Regulatory hold")) ownerSet.add("Legal");
    if (signals.includes("Overdue invoice")) ownerSet.add("Finance");
    if (signals.includes("Delayed shipment")) ownerSet.add("Customer Success");
    if (signals.includes("Usage decline")) ownerSet.add("Customer Success");
    if (signals.includes("Escalated support")) ownerSet.add("Support");

    const ownerOrder = ["Legal", "Finance", "Customer Success", "Support"];
    const owners = ownerOrder.filter(o => ownerSet.has(o));

    const status = qualifies
      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
      : "Monitoring — no escalation required.";

    const riskSummary = signals.length > 0
      ? `${signals.length} signals: ${signals.join(", ")}`
      : "0 signals";

    const nextStep = qualifies
      ? `${owners[0]} recovery review by 16:00`
      : "Continue standard monitoring.";

    const requestId = reqRow?.request_id || "req-workflow";

    // Clean slate
    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    // workflow_state
    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, "Strategic account rescue", status, nextStep, riskSummary]
    );

    // owner_tasks (in fixed order)
    if (qualifies) {
      for (const owner of owners) {
        await client.query(
          "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
          [requestId, accountId, owner, `${owner} recovery review for ${account.name}`, now, "open"]
        );
      }
    }

    // customer_messages (customer-safe, no internal ids)
    const customerMessage = qualifies
      ? `We are reaching out regarding your account with us. Our team has identified several areas requiring immediate attention, including regulatory compliance, billing, shipment delays, support escalation, and usage trends. ` +
        `Dedicated teams are now actively coordinating on your behalf to resolve these matters and restore full service levels as quickly as possible. ` +
        `You will be contacted shortly by our recovery team with a detailed action plan and timeline. We appreciate your continued partnership and are committed to resolving these issues promptly.`
      : `Your account is currently in good standing. Our team continues to monitor your account health and will reach out if any action is required. Thank you for your continued partnership.`;

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [requestId, accountId, customerMessage]
    );

    // audit_events
    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, `Account rescue workflow initiated. ${riskSummary}. Recovery owners notified.`, now, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

