1	// Optional helper: pure functions implementing RULES.md against a normalized
2	// fact bundle { account, invoices, shipments, regulatoryFlags, supportCases, usage }.
3	// Using this is allowed; the facts still come from the live DB you must read.
4	export const RULES = {
5	  "invoiceHighCents": 2500000,
6	  "usageDropFraction": 0.3,
7	  "qualifyingTiers": [
8	    "strategic",
9	    "enterprise"
10	  ],
11	  "highSupportSeverities": [
12	    "high",
13	    "critical"
14	  ],
15	  "escalationStatus": "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
16	  "monitorStatus": "Monitoring — no escalation required."
17	};
18	const OWNER_FOR = { regulatory: "Legal", invoice: "Finance", shipment: "Customer Success", usage: "Customer Success", support: "Support" };
19	const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
20	const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
21	const SIGNAL_NAME = { regulatory: "Regulatory hold", invoice: "Overdue invoice", shipment: "Delayed shipment", support: "Escalated support", usage: "Usage decline" };
22	const ms = (d) => Date.parse(d);
23	
24	export function firedRisks(f, now) {
25	  const n = ms(now), out = {};
26	  if ((f.invoices||[]).some((i)=>i.status!=="paid"&&ms(i.dueDate)<n&&i.amountCents>=RULES.invoiceHighCents)) out.invoice=1;
27	  if ((f.shipments||[]).some((s)=>!s.deliveredDate&&ms(s.slaDate)<n)) out.shipment=1;
28	  if ((f.regulatoryFlags||[]).some((r)=>r.status==="open")) out.regulatory=1;
29	  if ((f.supportCases||[]).some((c)=>c.status==="open"&&RULES.highSupportSeverities.includes(c.severity))) out.support=1;
30	  const u=f.usage||{};
31	  if (typeof u.priorPeriodUnits==="number"&&u.priorPeriodUnits>0&&u.currentPeriodUnits<=u.priorPeriodUnits*(1-RULES.usageDropFraction)) out.usage=1;
